LATITUDE = -21.19530173974597
LONGITUDE = -50.46757302669357
START_DATE = "2025-09-08"
END_DATE = "2025-09-08"

# In the START_DATE & END_DATE range, there can be multiple images. This index is used to select one of them.
IMAGE_INDEX = 0

"""
## **3. From 10m Sentinel-2 bands to 2.5m**


This example demonstrates the use of the `SEN2SRLite NonReference_RGBN_x4` model variant to enhance the spatial resolution
of only the 10 m Sentinel-2 bands: red (B04), green (B03), blue (B02), and near-infrared (B08). A Sentinel-2 L2A data cube is created using the cubo library for a specific location and date range. The input is normalized and passed to a pretrained non-reference model optimized for RGB+NIR inputs.
"""

import mlstac
import torch
import cubo

# Load the model
mlstac.download(
  file="https://huggingface.co/tacofoundation/sen2sr/resolve/main/SEN2SR/NonReference_RGBN_x4/mlm.json",
  output_dir="model/SEN2SR_RGBN",
)

# Create a Sentinel-2 L2A data cube for a specific location and date range
da = cubo.create(
    lat=LATITUDE,
    lon=LONGITUDE,
    collection="sentinel-2-l2a",
    bands=["B04", "B03", "B02", "B08"],
    start_date=START_DATE,
    end_date=END_DATE,
    edge_size=128,
    resolution=10
)

# Prepare the data to be used in the model
device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
original_s2_numpy = (da[IMAGE_INDEX].compute().to_numpy() / 10_000).astype("float32")
X = torch.from_numpy(original_s2_numpy).float().to(device)
X = torch.nan_to_num(X, nan=0.0, posinf=0.0, neginf=0.0)

model = mlstac.load("model/SEN2SR_RGBN").compiled_model(device=device)

# Apply model
superX = model(X[None]).squeeze(0)

import matplotlib.pyplot as plt

fig, axes = plt.subplots(1, 2, figsize=(10, 5))

# Original
axes[0].imshow(X[[0, 1, 2], :, :].permute(1, 2, 0).cpu().numpy() * 1.5)
axes[0].set_title("Original")
axes[0].axis('off')

# Mejorada
axes[1].imshow(superX[[0, 1, 2], :, :].permute(1, 2, 0).cpu().numpy() * 1.5)
axes[1].set_title("Super-resolved")
axes[1].axis('off')

plt.tight_layout()